package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testWithRecordSeparator() {
        // Given
        String recordSeparator = "\n";

        // When
        CSVFormat newCsvFormat = csvFormat.withRecordSeparator(recordSeparator);

        // Then
        assertEquals(recordSeparator, newCsvFormat.getRecordSeparator());
    }

    @Test
    public void testWithRecordSeparatorReflectively() {
        // Given
        String recordSeparator = "\n";

        // When
        CSVFormat newCsvFormat = csvFormat.withRecordSeparator(recordSeparator);

        // Then
        try {
            assertEquals(recordSeparator, (String) newCsvFormat.getClass().getMethod("getRecordSeparator").invoke(newCsvFormat));
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    // Add more test methods for other scenarios if needed

}
